import{_ as t,o as a,c as i,S as s}from"./chunks/framework.DZlzLDBr.js";const m=JSON.parse('{"title":"Custom Delimiters","description":"","frontmatter":{},"headers":[],"relativePath":"Custom-Delimiters.md","filePath":"Custom-Delimiters.md","lastUpdated":null}'),n={name:"Custom-Delimiters.md"};function l(o,e,r,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="custom-delimiters" tabindex="-1">Custom Delimiters <a class="header-anchor" href="#custom-delimiters" aria-label="Permalink to &quot;Custom Delimiters&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="what-this-setting-does" tabindex="-1">What this setting does <a class="header-anchor" href="#what-this-setting-does" aria-label="Permalink to &quot;What this setting does&quot;">​</a></h2><p>Sprout uses <code>|</code> as the default card-field delimiter. If that conflicts with your note content (for example, heavy LaTeX), you can choose another delimiter.</p><h2 id="available-delimiters" tabindex="-1">Available delimiters <a class="header-anchor" href="#available-delimiters" aria-label="Permalink to &quot;Available delimiters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Character</th></tr></thead><tbody><tr><td>Pipe (default)</td><td><code>|</code></td></tr><tr><td>At sign</td><td><code>@</code></td></tr><tr><td>Tilde</td><td><code>~</code></td></tr><tr><td>Semicolon</td><td><code>;</code></td></tr></tbody></table><h2 id="changing-the-delimiter" tabindex="-1">Changing the delimiter <a class="header-anchor" href="#changing-the-delimiter" aria-label="Permalink to &quot;Changing the delimiter&quot;">​</a></h2><ol><li>Go to <strong>Settings → Storage → Card delimiter</strong>.</li><li>Select your preferred delimiter from the dropdown.</li></ol><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>With the <code>@</code> delimiter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T @ Title @</span></span>
<span class="line"><span>Q @ What is the capital of France? @</span></span>
<span class="line"><span>A @ Paris @</span></span>
<span class="line"><span>I @ Located on the River Seine @</span></span>
<span class="line"><span>G @ Geography @</span></span></code></pre></div><p>With the <code>~</code> delimiter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T ~ Title ~</span></span>
<span class="line"><span>Q ~ What is the capital of France? ~</span></span>
<span class="line"><span>A ~ Paris ~</span></span></code></pre></div><h2 id="important-limit" tabindex="-1">Important limit <a class="header-anchor" href="#important-limit" aria-label="Permalink to &quot;Important limit&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Changing the delimiter does not migrate existing cards. Cards written with the old delimiter stop parsing. On the next sync, those cards can lose scheduling linkage/progress.</p></div><p>Only change this on a fresh vault, or after manually converting all existing cards.</p><h2 id="when-to-change" tabindex="-1">When to change <a class="header-anchor" href="#when-to-change" aria-label="Permalink to &quot;When to change&quot;">​</a></h2><p>Most users should keep <code>|</code>. Consider changing only when needed:</p><ul><li>Your notes use many <code>|</code> characters in content (for example LaTeX).</li><li>Another workflow or plugin conflicts with pipe-delimited fields.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Before changing globally, try the multi-line pattern in <a href="./Card-Formatting">Card Formatting</a>. That often avoids delimiter conflicts without breaking existing cards.</p></div>`,20)])])}const u=t(n,[["render",l]]);export{m as __pageData,u as default};
